// Delhi micro-basin GeoJSON (generated from hotspot coords)
const DELHI_MICRO_BASIN_FEATURE_COLLECTION = {
    type: "FeatureCollection",
    features: DELHI_HOTSPOT_DATA.map(h => {
        const o = 0.001 + (h.fvi * 0.001); // Very small polygons for micro-level planning
        return {
            type: "Feature",
            properties: { ...h },
            geometry: {
                type: "Polygon",
                coordinates: [[
                    [h.lng - o, h.lat - o],
                    [h.lng + o, h.lat - o * 0.5],
                    [h.lng + o * 1.2, h.lat + o],
                    [h.lng - o * 0.5, h.lat + o * 1.1],
                    [h.lng - o, h.lat - o]
                ]]
            }
        };
    })
};

